ibs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"https://es.wordpress.org/2017/01/20/eventos-wordpress-para-la-semana-04-17/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2017/01/20/eventos-wordpress-para-la-semana-04-17/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 20 Jan 2017 10:42:43 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://es.wordpress.org/?p=1079\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:372:\"¡Buenos días a todos! Os dejamos el listado de las Meetups para esta semana como así también el avance de las organizaciones de las distintas WordCamps. Enhorabuena al nuevo grupo de Meetup de Valladolid y a los organizadores de la reciente publicada WordCamp Alicante. Meetups 24/01 &#8211; Madrid &#8211; Haciendo un buen uso de los campos personalizados [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Mauricio Gelves\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:5668:\"<p><strong>¡Buenos días a todos!</strong> Os dejamos el listado de las Meetups para esta semana como así también el avance de las organizaciones de las distintas WordCamps.<br />\nEnhorabuena al nuevo grupo de <a href=\"https://www.meetup.com/es-ES/Valladolid-WordPress-Meetup/\" target=\"_blank\">Meetup de Valladolid</a> y a los organizadores de la reciente publicada <a href=\"https://2017.alicante.wordcamp.org/\" target=\"_blank\">WordCamp Alicante</a>.</p>\n<hr />\n<h2>Meetups</h2>\n<ul>\n<li>24/01 &#8211; <strong>Madrid</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPress-Madrid/events/236911916/\" target=\"_blank\">Haciendo un buen uso de los campos personalizados con ACF</a></li>\n<li>24/01 &#8211; <strong>Sevilla</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPress-Sevilla/events/221757477/\" target=\"_blank\">Control de versiones: Git</a></li>\n<li>24/01 &#8211; <strong>Majadahonda</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPress-Majadahonda/events/236813537/\" target=\"_blank\">Dale a tu contenido el espacio que se merece &#8211; WordPress Custom Post Types</a></li>\n<li>25/01 &#8211; <strong>Zaragoza</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPress-Zaragoza/events/236815141/\" target=\"_blank\">Iniciación a Gravity Forms</a></li>\n<li>26/01 &#8211; <strong>Alcalá de Henares</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/Alcala-de-Henares-WordPress-Meetup/events/236024376/\" target=\"_blank\">Quedada para puesta en común de ideas, dudas e inquietudes sobre WordPress</a></li>\n<li>26/01 &#8211; <strong>Collado Villalba</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPress-Collado-Villalba-Meetup/events/236804775/\" target=\"_blank\">Trucos ocultos para convertirte en un Ninja de WordPress</a></li>\n<li>26/01 &#8211; <strong>Málaga</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPress-Malaga/events/236959119/\" target=\"_blank\">Comenzando con WordPress. Instalación y configuración. Trucos y consejos.</a></li>\n<li>26/01 &#8211; <strong>Valladolid</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/Valladolid-WordPress-Meetup/events/236821199/\" target=\"_blank\">Presentación Comunidad WordPress</a> (nuevo Meetup <strong><img src=\"https://s.w.org/images/core/emoji/2.2.1/72x72/1f389.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></strong>)</li>\n<li>27/01 &#8211; <strong>Granollers</strong> &#8211; <a href=\"https://www.meetup.com/es-ES/WordPressGranollers/events/236897558/\" target=\"_blank\">Taller Práctico, Ven con Tu Portátil <img src=\"https://s.w.org/images/core/emoji/2.2.1/72x72/1f609.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></a></li>\n</ul>\n<hr />\n<h2>WordCamps</h2>\n<p>Sigue de cerca la organización de los próximos WordCamps que se celebrarán en España durante el 2017.</p>\n<ul>\n<li><strong>WordCamp Madrid 22-23 de Abril 2017<br />\n</strong><a href=\"https://2017.madrid.wordcamp.org/\" target=\"_blank\">Web</a> | <a href=\"https://2017.madrid.wordcamp.org/llamada-a-patrocinadores-call-for-sponsors/\" target=\"_blank\">Llamada a patrocinadores</a> | <a href=\"https://2017.madrid.wordcamp.org/llamada-a-ponentes-call-for-speakers/\" target=\"_blank\">Llamada a ponentes<br />\n</a><img class=\"wp-image-1088\" src=\"https://es.wordpress.org/files/2017/01/wordcamp-madrid-2017-1024x341.png\" alt=\"WordCamp Madrid 2017\" width=\"308\" height=\"72\" /></li>\n<li><strong>WordCamp Bilbao 12-14 de Mayo 2017<br />\n</strong><a href=\"https://2017.bilbao.wordcamp.org/\" target=\"_blank\">Web</a> | <a href=\"https://2017.bilbao.wordcamp.org/llamada-a-patrocinadores/\" target=\"_blank\">Llamada a patrocinadores</a> | <a href=\"https://2017.bilbao.wordcamp.org/llamada-a-ponentes/\" target=\"_blank\">Llamada a ponentes</a> | <a href=\"http://2017.bilbao.wordcamp.org/llamada-voluntarios\" target=\"_blank\">Llamada a voluntarios</a> | <a href=\"https://2017.bilbao.wordcamp.org/compra-tu-entrada\" target=\"_blank\">Tickets <img src=\"https://s.w.org/images/core/emoji/2.2.1/72x72/1f39f.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></a><br />\n<img class=\"alignnone wp-image-1090\" src=\"https://es.wordpress.org/files/2017/01/wordpress-bilbao-2017.jpg\" alt=\"WordCamp Bilbao 2017\" width=\"311\" height=\"159\" /></li>\n<li><strong>WordCamp Alicante 4 de Marzo 2017</strong><br />\n<a href=\"https://2017.alicante.wordcamp.org/\" target=\"_blank\">Web</a> | <a href=\"https://2017.alicante.wordcamp.org/patrocina-el-evento/\" target=\"_blank\">Llamada a patrocinadores</a> | <a href=\"https://2017.alicante.wordcamp.org/llamada-a-ponentes/\" target=\"_blank\">Llamada a ponentes</a> | <a href=\"https://2017.alicante.wordcamp.org/llamada-a-voluntarios/\" target=\"_blank\">Llamada a voluntarios</a> | <a href=\"https://2017.alicante.wordcamp.org/tickets-wordcamp-alicante-2017/\" target=\"_blank\">Tickets <img src=\"https://s.w.org/images/core/emoji/2.2.1/72x72/1f39f.png\" alt=\"?\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></a><br />\n<img class=\"alignnone wp-image-1091\" src=\"https://es.wordpress.org/files/2017/01/wordcamp-alicante-2017.png\" alt=\"WordCamp Alicante 2017\" width=\"312\" height=\"156\" /></li>\n</ul>\n<hr />\n<h2>Otros eventos WordPress</h2>\n<p>Aquí podrás encontrar otros eventos interesantes en torno al mundo WordPress.</p>\n<ul>\n<li><strong>WPCampus Bilbao 24 de Marzo 2017<br />\n</strong><a href=\"https://2017.campuswp.es/\" target=\"_blank\">Web</a> | <a href=\"https://2017.campuswp.es/patrocina-wpcampus-2017/\" target=\"_blank\">Llamada a patrocinadores</a> | <a href=\"https://2017.campuswp.es/horario-academico/profesores/\" target=\"_blank\">Llamada a profesores</a></li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://es.wordpress.org/2017/01/20/eventos-wordpress-para-la-semana-04-17/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:42:\"\n		\n		\n		\n		\n		\n				\n\n		\n		\n				\n			\n		\n		\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:5:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:22:\"Eventos para la semana\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"https://es.wordpress.org/2017/01/16/eventos-wordpress-para-la-semana-03-17/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://es.wordpress.org/2017/01/16/eventos-wordpress-para-la-semana-03-17/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 16 Jan 2017 11:17:25 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:1:{i:0;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://es.wordpress.org/?p=1074\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:37