	(6246,748,'id_Descripcion_narracion_Es','            \r\n<!-- BIBLIOTECAS A -->\r\n  <div class=\"letra_biblioteca_abecedario\">A</a> </div>\r\n\r\n  <div class=\"descripcion_biblioteca\">\r\n    <a href=\"http://132.248.9.34/hevila/ConvergenciaRevistadelsocialismochilenoylatinoamericano/1988/no13/4.pdf\" target=\"_blank\">\r\n      <b>ALLENDE, Salvador.</b>(1988) Carta de Salvador Allende al Partido Comunista. Revista del socialismo, 13, 23-26.\r\n    </a>\r\n  </div>\r\n\r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://132.248.9.34/hevila/ConvergenciaRevistadelsocialismochilenoylatinoamericano/1991/no19-20/5.pdf\" target=\"_blank\">\r\n    <b>ALLENDE, Salvador.</b>(1991) Allende y la masonería. Convergencia. Revista del socialismo, 19-20, 27.\r\n  </a> \r\n</div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://132.248.9.34/hevila/ConvergenciaRevistadelsocialismochilenoylatinoamericano/1990/no18/2.pdf\" target=\"_blank\">\r\n    <b>ALMEYDA, Clodomiro.</b>(1991) Homenaje a Salvador Allende, cementerio Santa Inés. Convergencia. Revista del socialismo, 19, 9.\r\n</a> </div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://www.scielo.cl/scielo.php?script=sci_arttext&pid=S0717-71942010000200001&lang=pt\" target=\"_blank\">\r\n    <b>ALVAREZ VALLEJOS, Rolando.</b>(2010) ¿Represión o integración? La política sindical del Régimen Militar. 1973-1980. Historia, 43 (2), 325-355.\r\n</a> </div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"https://www.rebelion.org/hemeroteca/chile/030827allende.htm\" target=\"_blank\">\r\n    <b>AMOROS, Mario.</b>(2013) Salvador Allende. Un revolucionario para el siglo XXI. El Viejo Topo, 308, 20-25.\r\n</a> </div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://132.248.9.34/hevila/ConvergenciaRevistadelsocialismochilenoylatinoamericano/1991/no19-20/4.pdf\" target=\"_blank\">\r\n    <b>ARANCIBIA, Armando.</b>(1991) Salvador Allende, precursor. Convergencia. Revista del socialismo, 19-20, 24-25.\r\n</a> </div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://repositorio.uchile.cl/handle/2250/109938\" target=\"_blank\">\r\n    <b>ARÁNGUIZ, Stephanie; Maldonado.</b>(2010) ¡¡Crear, crear, Poder Popular!! : consigna, utopía y constructo histórico. Universidad de Chile.\r\n</a> </div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://www.scielo.cl/scielo.php?script=sci_arttext&pid=S0718-04622009000100010&lang=pt\" target=\"_blank\">\r\n    <b>ARELLANO, Juan Carlos.</b>(2009) El Partido Nacional en Chile: su rol en el conflicto político (1966-1973). Atenea, 499, 157-174.\r\n</a> </div> \r\n\r\n <div class=\"descripcion_biblioteca\">\r\n	<a href=\"#\" target=\"_blank\">\r\n    <b>ARRATE, Jorge.</b>(1988) Salvador Allende y la renovación socialista. Revista del socialismo, 13, 14-22.\r\n</a> </div> \r\n\r\n<div class=\"descripcion_biblioteca\">\r\n	<a href=\"http://132.248.9.34/hevila/ConvergenciaRevistadelsocialismochilenoylatinoamericano/1990/no18/2.pdf\" target=\"_blank\">\r\n    <b>ARRATE, Jorge.</b>(1990) Palabras de Jorge Arrate, secretario general del Partido Socialista. Revista del socialismo, 18, 11.\r\n</a> </div> \r\n\r\n\r\n<!-- BIBLIOTECAS B -->\r\n\r\n  <div class=\"letra_biblioteca_abecedario\">B</div>\r\n\r\n\r\n<div class=\"descripcion_biblioteca\">\r\n<a href=\"http://repositorio.uchile.cl/handle/2250/116706\" target=\"_blank\">\r\n  <b>BARROS CAJDLER, Daniel.</b>(2013) Estatización de la industria textil durante el gobierno de la Unidad popular (1970-1973). Universidad de Chile, 464.\r\n</a> </div>\r\n\r\n\r\n<div class=\"descripcion_biblioteca\">\r\n<a href=\"http://laberinto.uma.es/index.php?option=com_content&view=article&id=182:la-muerte-del-presidente-allende-30-anos-despues&catid=47:lab13&Itemid=54\" target=\"_blank\">\r\n  <b>BENITEZ, Hermes.</b>(2004) La muerte del presidente Allende: 30 años después. Filosofía,política y economía en el La…, 5.  \r\n</